/**
 * @param {number[]} nums
 * @param {number} k
 * @return {number}
 */
var maxTotalValue = function(nums, k) {
    const n = nums.length;
    let min = nums[0];
    let max = nums[0];

    for (let i = 1; i < n; i++) {
        if (nums[i] < min) {
            min = nums[i];
        } else if (nums[i] > max) {
            max = nums[i];
        }
    }

    return (max - min) * k;
};

/**
 * @param {number[]} nums
 * @param {number} k
 * @return {number}
 */
var maxTotalValue = function(nums, k) {
    const n = nums.length;
    const diff = [];

    for (let i = 0; i < n - 1; i++) {
        let min = nums[i];
        let max = nums[i];

        for (let j = i + 1; j < n; j++) {
            if (nums[j] < min) min = nums[j];
            else if (nums[j] > max) max = nums[j];

            diff.push(max - min);
        }
    }

    diff.sort((a, b) => b - a);

    return diff.slice(0, k).reduce((acc, el) => acc + el, 0);
};
